import{_ as a,o as s,c as l,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Chat Channels","description":"","frontmatter":{"summary":"Messaging platforms OpenSoul can connect to","read_when":["You want to choose a chat channel for OpenSoul","You need a quick overview of supported messaging platforms"],"title":"Chat Channels"},"headers":[],"relativePath":"channels/index.md","filePath":"channels/index.md","lastUpdated":1771906665000}'),t={name:"channels/index.md"};function o(i,e,r,c,h,d){return s(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="chat-channels" tabindex="-1"><a class="header-anchor" href="#chat-channels">#</a> Chat Channels</h1><p>OpenSoul can talk to you on any chat app you already use. Each channel connects via the Gateway. Text is supported everywhere; media and reactions vary by channel.</p><h2 id="supported-channels" tabindex="-1"><a class="header-anchor" href="#supported-channels">#</a> Supported channels</h2><ul><li><a href="/docs/channels/whatsapp">WhatsApp</a> — Most popular; uses Baileys and requires QR pairing.</li><li><a href="/docs/channels/telegram">Telegram</a> — Bot API via grammY; supports groups.</li><li><a href="/docs/channels/discord">Discord</a> — Discord Bot API + Gateway; supports servers, channels, and DMs.</li><li><a href="/docs/channels/slack">Slack</a> — Bolt SDK; workspace apps.</li><li><a href="/docs/channels/feishu">Feishu</a> — Feishu/Lark bot via WebSocket (plugin, installed separately).</li><li><a href="/docs/channels/googlechat">Google Chat</a> — Google Chat API app via HTTP webhook.</li><li><a href="/docs/channels/mattermost">Mattermost</a> — Bot API + WebSocket; channels, groups, DMs (plugin, installed separately).</li><li><a href="/docs/channels/signal">Signal</a> — signal-cli; privacy-focused.</li><li><a href="/docs/channels/bluebubbles">BlueBubbles</a> — <strong>Recommended for iMessage</strong>; uses the BlueBubbles macOS server REST API with full feature support (edit, unsend, effects, reactions, group management — edit currently broken on macOS 26 Tahoe).</li><li><a href="/docs/channels/imessage">iMessage (legacy)</a> — Legacy macOS integration via imsg CLI (deprecated, use BlueBubbles for new setups).</li><li><a href="/docs/channels/msteams">Microsoft Teams</a> — Bot Framework; enterprise support (plugin, installed separately).</li><li><a href="/docs/channels/line">LINE</a> — LINE Messaging API bot (plugin, installed separately).</li><li><a href="/docs/channels/nextcloud-talk">Nextcloud Talk</a> — Self-hosted chat via Nextcloud Talk (plugin, installed separately).</li><li><a href="/docs/channels/matrix">Matrix</a> — Matrix protocol (plugin, installed separately).</li><li><a href="/docs/channels/nostr">Nostr</a> — Decentralized DMs via NIP-04 (plugin, installed separately).</li><li><a href="/docs/channels/tlon">Tlon</a> — Urbit-based messenger (plugin, installed separately).</li><li><a href="/docs/channels/twitch">Twitch</a> — Twitch chat via IRC connection (plugin, installed separately).</li><li><a href="/docs/channels/zalo">Zalo</a> — Zalo Bot API; Vietnam&#39;s popular messenger (plugin, installed separately).</li><li><a href="/docs/channels/zalouser">Zalo Personal</a> — Zalo personal account via QR login (plugin, installed separately).</li><li><a href="/docs/web/webchat">WebChat</a> — Gateway WebChat UI over WebSocket.</li></ul><h2 id="notes" tabindex="-1"><a class="header-anchor" href="#notes">#</a> Notes</h2><ul><li>Channels can run simultaneously; configure multiple and OpenSoul will route per chat.</li><li>Fastest setup is usually <strong>Telegram</strong> (simple bot token). WhatsApp requires QR pairing and stores more state on disk.</li><li>Group behavior varies by channel; see <a href="/docs/channels/groups">Groups</a>.</li><li>DM pairing and allowlists are enforced for safety; see <a href="/docs/gateway/security/index">Security</a>.</li><li>Telegram internals: <a href="/docs/channels/grammy">grammY notes</a>.</li><li>Troubleshooting: <a href="/docs/channels/troubleshooting">Channel troubleshooting</a>.</li><li>Model providers are documented separately; see <a href="/docs/providers/models">Model Providers</a>.</li></ul>',6)])])}const g=a(t,[["render",o]]);export{u as __pageData,g as default};
